        deprecated = set()
        for ver, mods in self.DEPRECATED_MODULES.items():
            if current >= (ver, 0):
                deprecated.update(mods)
        return deprecated

    def _should_skip_directory(self, pyfile: Path) -> bool:
        """Check if file should be skipped due to being in an irrelevant directory."""
        skip_patterns = ["__pycache__", ".git", "venv", "node_modules", ".tox", "build", "dist"]
        return any(pattern in pyfile.parts for pattern in skip_patterns)

    def _process_file(self, pyfile: Path, deprecated: set[str]) -> list["DiagnosticResult"]:
        """Process a single Python file for deprecated imports."""
        from ..types import DiagnosticResult
        results = []
        try:
            source = pyfile.read_text()
            tree = ast.parse(source)
            for node in ast.walk(tree):
                if isinstance(node, (ast.Import, ast.ImportFrom)):
                    modules_to_check = []
                    if isinstance(node, ast.Import):
                        modules_to_check = [alias.name for alias in node.names]
                    elif isinstance(node, ast.ImportFrom):
                        if node.module:
                            modules_to_check = [node.module]
                    for module in modules_to_check:
                        if module in deprecated:
                            results.append(DiagnosticResult(
                                category=self.category,
                                check_name="deprecated_import",
                                status="warning",
                                message=f"Deprecated module: {module}",
                                details={
                                    "module": module,
                                    "deprecated_since": self._get_deprecated_version(module),
                                },
                                suggestion=f"Replace {module} with modern alternative",
                                auto_fixable=False,
                                abs_path=str(pyfile),
                            ))
        except (OSError, SyntaxError) as e:
            # Log specific errors for debugging, but continue processing other files
            import logging
            logging.warning(f"Error processing {pyfile}: {e}")
        except Exception as e:
            # Fallback for unexpected errors, maintaining silent handling for compatibility
            import logging
            logging.error(f"Unexpected error processing {pyfile}: {e}")
        return results

    def _check_deprecated_imports(self, project_root: Path) -> list["DiagnosticResult"]:
        """Check for deprecated stdlib imports."""
        from ..types import DiagnosticResult

        results = []
        current = sys.version_info[:2]
        deprecated = self._get_deprecated_modules(current)
        if not deprecated:
            return results

        for pyfile in project_root.rglob("*.py"):
            if self._should_skip_directory(pyfile):
                continue
            results.extend(self._process_file(pyfile, deprecated))
        return results
